def iterative_retrieve_with_citations(question: str, retriever, max_iterations: int = 4) -> dict:
    all_docs = []
    seen = set()
    current_query = question
    citation_map = {}   # citation_number → Document

    for i in range(max_iterations):
        docs = retriever.invoke(current_query)
        for doc in docs:
            h = hash(doc.page_content)
            if h not in seen:
                seen.add(h)
                cit_num = len(citation_map) + 1
                citation_map[cit_num] = doc
                all_docs.append((cit_num, doc))

        context = "\n\n".join(f"[{n}] {d.page_content}" for n, d in all_docs)
        sufficiency = llm.invoke(
            f"Question: {question}\nContext:\n{context[:3500]}\n\n"
            "Enough to answer? Reply YES: <answer with [N] citations> or NO: <next query>"
        ).content.strip()

        if sufficiency.startswith("YES:"):
            return {"answer": sufficiency[4:].strip(), "citations": citation_map}

        if sufficiency.startswith("NO:"):
            current_query = sufficiency[3:].strip()

    context = "\n\n".join(f"[{n}] {d.page_content}" for n, d in all_docs)
    answer = llm.invoke(f"Context:\n{context}\n\nAnswer with [N] citations: {question}").content
    return {"answer": answer, "citations": citation_map}
